-- 技術用語単語帳アプリ：初期データ（seed）
-- schema.sql を実行したあとに Supabase の SQL Editor で実行してください。

INSERT INTO words (term, description, example, category) VALUES
-- Java
('オブジェクト指向', '物や役割ごとに「クラス」という設計図を作り、それをもとに実際の「オブジェクト」を作る考え方。役割を分けることで修正しやすくなる。', '車の設計図（クラス）を作っておけば同じ設計図から何台でも車（インスタンス）が作れるイメージ。', 'java'),
('インスタンス', 'クラスという設計図から実際に作られた「モノ」のこと。new キーワードで生成する。', '「車の設計図（クラス）」から作られた「実際の1台の車」がインスタンス。', 'java'),
('クラス', 'フィールド（変数）とメソッド（処理）をひとまとめにした設計図。同じ種類のデータと処理を1か所で管理できる。', 'たい焼きの型（クラス）があれば、同じ形のたい焼き（インスタンス）を何個でも作れる。', 'java'),
('メソッド', 'クラスの中に書く「処理のまとまり」。何度も使う処理をメソッドにまとめておくとコードが短くなり読みやすくなる。', '「お茶を出す」という動作（メソッド）を定義しておけば、何度でも呼び出せる。', 'java'),
('フィールド', 'クラスの中で持つ変数のこと。そのオブジェクトの「状態」を保持する。基本的にprivateにして外から直接触れないようにする。', '人物クラスで「名前」「年齢」などを保持する変数がフィールド。', 'java'),
('private / public', 'アクセス修飾子。privateはそのクラス内からしかアクセスできない。publicはどこからでもアクセスできる。フィールドはprivateが基本。', 'private＝社員専用の裏口、public＝誰でも入れる正面玄関のイメージ。', 'java'),
('getter / setter', 'privateにしたフィールドの値を取得（get）・変更（set）するためのメソッド。外から直接触れない代わりにこれを通じて操作する。', '銀行の窓口（getter/setter）を通してしかお金（フィールド）を動かせない仕組み。', 'java'),
('try-catch-finally', 'エラーが起きても処理を止めずにコントロールする仕組み。tryでエラーになりそうな処理を囲み、catchでエラー時の対応、finallyで必ず実行する処理を書く。', '料理中に焦がしても（エラー）換気（catch）と後片付け（finally）は必ずやる、みたいなイメージ。', 'java'),
('例外（Exception）', 'プログラムの実行中に起きる想定外のエラーのこと。try-catchで捕まえて対処する。', '「ファイルが見つからない」「数字以外が入力された」など、予期せぬ出来事が例外。', 'java'),
('List', '順番があるデータの集まり。重複する値もOK。上から順に処理したいときに使う。ArrayListが最もよく使われる。', '買い物リストのように、順番があって同じものが2回あってもOK。', 'java'),
('Map', 'キーと値をセットにして持つコレクション。キーを指定することで対応する値をすぐ取り出せる。HashMapが代表的。', '辞書みたいなもの。「単語（キー）」を引けば「意味（値）」がすぐ出てくる。', 'java'),
('for文 / 拡張for文', '繰り返し処理。通常のforは回数指定、拡張for（for-each）はリストなどの要素を1つずつ取り出すのに使う。', '「リストの全員に案内を送る」処理を拡張forで1人ずつ取り出してメール送信するイメージ。', 'java'),
('null', '「何もない」「値が入っていない」状態を表す特別な値。nullのまま処理しようとするとNullPointerExceptionが発生する。', '空っぽの箱（null）を開けようとするとエラーになる。開ける前に中身確認が必要。', 'java'),
('Struts2', 'JavaでWebアプリを作るためのフレームワーク。画面（JSP）と処理（Action）を分けて管理するMVCパターンで動く。現職の社内システムで使用中。', 'レストランで「注文を受ける人（Action）」と「料理を出す（JSP）」を分けて管理する厨房のルール。', 'java'),
('Actionクラス', 'Struts2でHTTPリクエストを受け取って処理を行うクラス。画面からの入力を受け取り、DBと連携して結果をJSPに渡す。', '注文を受けて厨房に伝える「ウェイター」のような役割。', 'java'),
('JSP', 'JavaでHTMLを動的に生成するためのテンプレートファイル。Actionから受け取ったデータを画面に表示する役割を担う。', 'HTMLに「ここにJavaの値を入れて！」と指示できるようにしたもの。', 'java'),
('Formクラス', 'Struts2で画面の入力値を受け取るためのクラス。入力フォームの各項目をフィールドとして持つ。', '注文用紙（フォーム）に記入された内容を保管する入れ物。', 'java'),
('インターセプター', 'Struts2でActionの処理の前後に共通処理を挟む仕組み。ログイン確認やログ出力などを毎回書かずに済む。', 'お店の入口でセキュリティチェック（ログイン確認）を自動でやってくれる人。', 'java'),
('MVCパターン', 'Model（データ）・View（画面）・Controller（制御）に分けてアプリを設計する考え方。役割を分けることで修正しやすくなる。', '料理（Model）・皿盛り（View）・指示を出すシェフ（Controller）が分業するイメージ。', 'java'),
('DAO（Data Access Object）', 'DBへのアクセス処理をまとめたクラス。SQLの実行はDAOに集めることで、ロジック側はDBの詳細を気にしなくてよくなる。', '「DB担当の専門窓口」。他のクラスはDAOに頼めばDBのことは任せられる。', 'java'),
('コンストラクタ', 'クラスからインスタンスを生成するときに自動で呼ばれる初期化メソッド。クラス名と同じ名前で定義する。', '新入社員が入社したとき（インスタンス生成）に必ず行われる初期設定（コンストラクタ）。', 'java'),
('オーバーライド', '親クラスのメソッドを子クラスで上書きすること。@Overrideアノテーションを付けて書く。', '親から引き継いだレシピを、子が自分流にアレンジして使うイメージ。', 'java'),
('インターフェース', 'クラスが実装すべきメソッドの一覧を定義したもの。「何ができるか」を約束させる仕組み。', '「このアプリを出すにはこの機能が必要」という契約書のようなもの。', 'java'),
-- DB・SQL
('SELECT文', 'DBからデータを取り出すSQL。WHEREで条件を絞り、ORDER BYで並び替え、LIMITで件数を制限できる。', '「名簿の中から大阪在住の人を、名前順で10人だけ出して」という命令。', 'db'),
('INSERT文', 'DBに新しいデータを追加するSQL。VALUESに追加する値を書く。INSERT SELECTを使うとSELECTの結果をそのまま追加できる。', '名簿に新しい人を1行追加する命令。', 'db'),
('UPDATE文', 'DBのデータを更新するSQL。WHEREで対象を絞り忘れると全行が変わってしまうので要注意。', 'WHEREを付けずにUPDATEすると全員の情報が書き換わる。絶対に条件を忘れずに。', 'db'),
('DELETE文', 'DBからデータを削除するSQL。WHEREを忘れると全件削除になるので要注意。', '条件なしのDELETEはテーブルが空になる。本番では特に慎重に。', 'db'),
('WHERE句', 'SELECT・UPDATE・DELETEで対象行を絞り込む条件を書く部分。AND/ORで複数条件を組み合わせられる。', '「年齢が20以上 AND 大阪在住」のように条件を重ねて絞る。', 'db'),
('JOIN（テーブル結合）', '複数のテーブルを関連するカラムで繋いで1つの結果として取り出す方法。INNER JOINは両方に存在する行のみ、LEFT JOINは左側の全行を返す。', '社員テーブルと部署テーブルを社員IDで繋いで「誰がどの部署か」を1度に取り出す。', 'db'),
('サブクエリ', 'SQL文の中にさらにSELECT文を入れる書き方。同じテーブルを参照するときはASで別名をつける必要がある（MySQLの制約）。', '「最高点を取った人を検索」→ まず最高点をSELECTして、その値で絞り込む。', 'db'),
('COALESCE関数', '値がNULLだったときに代わりの値を返す関数。COALESCE(値, デフォルト値)の形で書く。MAX()などがNULLを返す可能性があるときに使う。', 'COALESCE(MAX(SORT), 0) + 1 → SORTが0件ならMAXはNULL→0を返す→1から始まる。実際の業務で使った。', 'db'),
('トランザクション', '複数のDB処理をひとまとまりとして扱う仕組み。途中でエラーが起きたら全部なかったことにする（ロールバック）、全部成功したら確定（コミット）。', '銀行振込で「口座Aから引く＋口座Bに足す」がセット。片方だけ失敗したら両方取り消す。', 'db'),
('ページネーション', '大量のデータを一定件数ずつ分けて表示する仕組み。LIMITとOFFSETのSQLで実現する。実務で実装した。', '検索結果を「1ページ10件」に区切って「次のページ」ボタンで送る仕組み。', 'db'),
('インデックス', 'テーブルの検索を速くするための仕組み。よく検索するカラムに設定する。設定しすぎると更新が遅くなるデメリットもある。', '本の目次（インデックス）があれば全ページ読まなくてもすぐ探せる。', 'db'),
('主キー（PRIMARY KEY）', 'テーブルの各行を一意に識別するカラム。重複不可・NULL不可。通常はIDカラムに設定する。', '社員番号のようなもの。同じ番号を持つ人は存在できない。', 'db'),
('外部キー（FOREIGN KEY）', '別テーブルの主キーを参照するカラム。テーブル間の関連を表し、参照整合性を保つ。', '注文テーブルに「顧客ID」があり、顧客テーブルの主キーを指している。', 'db'),
-- フロントエンド
('コンポーネント', 'UIの部品のこと。ボタン・ヘッダー・カードなど再利用できる単位に分けたもの。Reactではこの単位で開発する。', 'レゴブロックの1個1個がコンポーネント。組み合わせてページを作る。', 'front'),
('useState', 'Reactで画面に表示するデータ（状態）を管理するhook。値が変わると画面が自動で再描画される。', 'いいね数が増えると自動で数字が書き換わるのはuseStateが管理しているから。', 'front'),
('useEffect', 'Reactでコンポーネントの表示後や状態変化後に処理を実行するhook。APIからのデータ取得などに使う。', '画面が開いたら自動でデータを読み込む、という処理をuseEffectで書く。', 'front'),
('props', '親コンポーネントから子コンポーネントにデータを渡す仕組み。子は受け取ったpropsを使うだけで直接変更はできない。', '親から子へのお手紙（props）。子は読めるけど書き直せない。', 'front'),
('TypeScript', 'JavaScriptに型（数値・文字列・配列など）を追加した言語。型があることでバグを早期に発見できる。', '「ここには数字しか入れてはダメ」というルールをコードに書ける、強化版JavaScript。', 'front'),
('Tailwind CSS', 'クラス名を使って直接スタイルを当てるCSSフレームワーク。HTMLにクラスを書くだけでデザインが完成する。', 'text-lg font-bold text-blue-500 のようにクラスを並べてデザインする。', 'front'),
('非同期処理（async/await）', '時間のかかる処理（API通信・ファイル読み込みなど）を「待ってから次の処理に進む」書き方。awaitで処理が終わるまで一時停止する。', '「ピザを注文して（await）、届いてから食べる」という順番を守る書き方。', 'front'),
('API', '他のシステムやサーバーと「データのやり取り」をするための窓口。fetchやaxiosでリクエストを送り、JSONで結果を受け取る。', 'レストランのメニュー表（API）。「これをください」と頼むと料理（データ）が届く。', 'front'),
('JSON', 'データをやり取りするための書き方（形式）。キーと値のセットで書く。APIのレスポンスはほぼJSONで返ってくる。', '{"name": "石黒", "age": 30} のような形式で書いたデータの入れ物。', 'front'),
-- ツール
('Git', 'コードの変更履歴を管理するツール。commitで履歴を保存、branchで並行作業、mergeで合流する。', 'ゲームのセーブデータ管理。いつでも過去の状態に戻れる。', 'tool'),
('GitHub', 'Gitの履歴をオンラインで共有・管理するサービス。チームで同じコードを扱うときに必須。', 'Gitのセーブデータを置く「共有ロッカー」。チーム全員がアクセスできる。', 'tool'),
('Eclipse', 'Java開発でよく使われるIDE（統合開発環境）。コード補完・デバッグ・ビルドなどが1つのツールでできる。現職で使用中。', 'Javaを書くための「全部入りの仕事机」。メモ帳とは違い、エラーも教えてくれる。', 'tool'),
('VSCode', '軽量で拡張性が高いエディタ。フロントエンド開発でよく使われる。訓練校ではこちらを使用。', 'シンプルだけど拡張機能を入れれば何でもできる「カスタマイズできる仕事机」。', 'tool'),
('Tomcat', 'JavaのWebアプリを動かすためのサーバーソフト。Struts2アプリを動かすために必要。現職で使用中。', 'Javaで作ったWebアプリを「公開・実行」するための土台。', 'tool'),
('A5:SQL Mk-2', 'MySQLなどのDBに接続してSQLを実行・確認できるツール。テーブルの中身を目で見て確認できる。現職で使用中。', 'DBの中身をExcelのように一覧で見たり、SQLを直接試したりできるツール。', 'tool'),
('Supabase', 'データベース・認証・APIなどをまとめて提供するBaaSサービス。PostgreSQLをベースにしている。訓練校で使用。', '「DB・ログイン機能・API」をパッケージで提供してくれるサービス。自分で全部作らなくていい。', 'tool'),
('Firebase', 'Googleが提供するBaaS。認証・DB（Firestore）・ストレージなどが使える。クイズアプリのユーザー登録で使用。', 'Supabaseと同じく「よく使う機能をまとめて提供」してくれるGoogleのサービス。', 'tool'),
-- 設計
('基本設計', '「何を作るか」を決める工程。画面のレイアウト・処理の流れ・テーブル構成などを決める。詳細設計の前に行う。', '家を建てる前に「部屋数・間取り」を決める設計図のようなもの。', 'design'),
('詳細設計', '基本設計をもとに「どう実装するか」を決める工程。メソッド名・引数・戻り値・処理の流れなどを細かく定義する。', '「カレーを作る」が基本設計、「玉ねぎを何分炒めるか」が詳細設計。', 'design'),
('単体テスト', 'メソッドやクラスなど、小さな単位が正しく動くか確認するテスト。実装直後に自分で行う。', '部品の出来栄えをひとつひとつ確認してから組み立てるイメージ。', 'design'),
('結合テスト', '複数の機能を繋いで全体として正しく動くか確認するテスト。単体テストで合格した後に行う。', '部品を組み立てた後に、全体として正常に動くか試走するイメージ。', 'design'),
('境界値テスト', '「20歳以上OK」なら19・20・21のように、条件の境目の前後を重点的にテストする考え方。バグが出やすい場所を狙い打つ。', '制限速度60kmなら59・60・61で試してみるのと同じ発想。', 'design'),
('影響範囲の調査', '機能を追加・修正するとき、どこに影響が出るかを洗い出す作業。DB・画面・バッチ・外部連携など幅広く確認する。', '壁を1枚動かすと、電気配線・水道管・構造に影響が出るかを確認するリフォームの事前調査。', 'design'),
('ページネーション設計', '一覧画面でデータを何件ずつ表示するかを決め、「前へ/次へ」ボタンで切り替える仕組みの設計。LIMIT・OFFSETとページ番号の計算が必要。', '実務でページネーション機能の追加を担当した。totalCount÷pageSizeで総ページ数を計算する。', 'design'),
-- その他
('フレームワーク', 'アプリ開発でよく使う処理をまとめてくれた「土台」。ゼロから作らなくてよいので開発が速くなる。Struts2・React・Next.jsなどが代表例。', '家を建てるときの「プレハブキット」。基本的な構造はすでにあり、自分はカスタマイズするだけ。', 'general'),
('デバッグ', 'プログラムのバグ（不具合）を見つけて修正する作業。System.out.printlnやEclipseのデバッガで変数の中身を確認する。', '料理の味がおかしいとき、どの調味料が原因か一つずつ確認するイメージ。', 'general'),
('リファクタリング', 'プログラムの動作を変えずに、コードの読みやすさや構造を改善すること。メソッドを分割したり変数名を分かりやすくしたりする。', '引き出しの中を整理整頓する作業。外から見た使い勝手は同じでも、中がきれいになる。', 'general'),
('コードレビュー', '自分が書いたコードを他の人に確認してもらうこと。バグや設計の問題を早期に発見できる。指摘は勉強のチャンス。', '作文を先生に添削してもらうイメージ。指摘されたことを次に活かす。', 'general'),
('ログ', 'プログラムの動作状況を記録したもの。エラー発生時の原因特定に使う。どこで何が起きたかを後から追いかけられる。', 'レストランの注文履歴。「何時に何をオーダーしたか」が後から確認できる。', 'general'),
('環境変数', 'パスワードやAPIキーなどをコードに直書きせず、外部から設定する仕組み。本番・開発・テストで値を切り替えるのにも使う。', '設定値をコードの外に置いておくイメージ。本番では本物、開発では偽物を使える。', 'general'),
('スタックトレース', 'エラーが発生したときに表示される「どこでエラーが起きたか」の記録。一番上が直接の原因で、下に行くほど呼び出し元になる。', '「4階で火災→3階の非常ベル→2階の警報→1階のセンサー」のようにエラーの経路が書いてある。', 'general'),
('HTTP / HTTPS', 'Webブラウザとサーバーがデータをやりとりするためのルール（プロトコル）。HTTPSは暗号化されていて安全。', '手紙のやりとりのルール。HTTPSは封筒を二重にして暗号化した手紙を送るイメージ。', 'general');
